    eaveOverhangMm: 600,
  };
}

export function toggleEdgeSlope(state: RoofState, edgeIdx: number): RoofState {
  const next = { ...state.edgeSlopes };
  next[edgeIdx] = !state.edgeSlopes[edgeIdx];
  return { ...state, edgeSlopes: next };
}

