const elementsById = useMemo(() => {
  if (temporaryVisibility === null) return elementsByIdRaw;
  const VIEW_DEF_KINDS = new Set<string>([
    'plan_view',
    'view_template',
    'viewpoint',
    'sheet',
    'schedule',
    'level',
