      (temporaryVisibility.elementIds ?? []).includes(id);
    const visible = temporaryVisibility.mode === 'isolate' ? inSet : !inSet;
    if (visible) next[id] = el;
  }
  return next;
}, [elementsByIdRaw, temporaryVisibility]);
